+function drawTiledWall(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  // Enhanced stone wall rendering with bricks, mortar, depth shading, moss, and damage
+  const baseColors: Record<CharacterType, string> = {
+    king: '#3e3650', nobility: '#3a3850', knight: '#384050', squire: '#384038',
+    healer: '#303850', sentinel: '#303848', scribe: '#3a3430', judge: '#383040', blacksmith: '#383028',
+  };
+  const mortarColor = '#2a2a3a';
+  const brickBase = baseColors[type] || '#383038';
+  const brickLight = shadeColor(brickBase, 20);
+  const brickDark = shadeColor(brickBase, -20);
+  const mossColor = '#2a4a2a';
+  const damageColor = '#1a1a2a';
+  const brickWidth = 20;
+  const brickHeight = 10;
+  const seed = x * 7 + y * 13;
+
+  ctx.fillStyle = brickBase;
+  ctx.fillRect(x, y, w, h);
+
+  for (let row = 0; row < Math.ceil(h / brickHeight); row++) {
+    const offsetX = (row % 2) * (brickWidth / 2);
+    for (let col = -1; col < Math.ceil(w / brickWidth) + 1; col++) {
+      const bx = x + col * brickWidth + offsetX;
+      const by = y + row * brickHeight;
+      if (bx + brickWidth < x || bx > x + w) continue;
+
+      // Base brick color with subtle random shading for depth
+      const hash = ((bx * 31 + by * 17 + seed) & 0xFF) / 255;
+      let brickColor = brickBase;
+      if (hash > 0.7) brickColor = brickLight;
+      else if (hash < 0.3) brickColor = brickDark;
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(bx + 1, by + 1, brickWidth - 2, brickHeight - 2);
+
+      // Draw mortar lines (top and left edges)
+      ctx.fillStyle = mortarColor;
+      ctx.fillRect(bx, by, brickWidth, 2);
+      ctx.fillRect(bx, by, 2, brickHeight);
+
+      // Add subtle depth shading: highlight bottom-right edges
+      ctx.fillStyle = shadeColor(brickColor, 15);
+      ctx.fillRect(bx + brickWidth - 3, by + 2, 2, brickHeight - 4);
+      ctx.fillRect(bx + 2, by + brickHeight - 3, brickWidth - 4, 2);
+
+      // Add random moss patches on bricks
+      if (hash > 0.5 && hash < 0.6) {
+        ctx.fillStyle = mossColor;
+        ctx.fillRect(bx + 4, by + 3, 3, 2);
+        ctx.fillRect(bx + 10, by + 6, 4, 2);
+      }
+
+      // Add random damage spots
+      if (hash < 0.15) {
+        ctx.fillStyle = damageColor;
+        ctx.fillRect(bx + 6, by + 4, 2, 2);
+        ctx.fillRect(bx + 12, by + 2, 3, 3);
+      }
+    }
+  }
+
+  // Soft highlight line on top of wall for light reflection
+  ctx.fillStyle = 'rgba(255,255,255,0.08)';
+  ctx.fillRect(x, y, w, 3);
+}
